import crypto from "node:crypto";
import fs from "node:fs";
import path from "node:path";

const root = process.cwd();
const version = "0.1.1";
const source = path.join(root, "assets", "interface", `v${version}`);
const manifest = JSON.parse(
  fs.readFileSync(path.join(source, "manifest.json"), "utf8"),
);
const stylesheet = "atlas-interface-kit.css";
const output = path.join(root, "src", "interface-bundle.generated.js");

function sha256(buffer) {
  return crypto.createHash("sha256").update(buffer).digest("hex");
}

if (
  manifest.version !== version ||
  manifest.contract_version !== "2.0.0"
) {
  throw new Error("unexpected Atlas interface bundle version or contract");
}

for (const [filename, record] of Object.entries(manifest.files || {})) {
  const buffer = fs.readFileSync(path.join(source, filename));
  if (
    buffer.byteLength !== record.bytes ||
    sha256(buffer) !== record.sha256
  ) {
    throw new Error(
      `Atlas interface bundle fingerprint mismatch: ${filename}`,
    );
  }
  if (filename.endsWith(".json")) JSON.parse(buffer.toString("utf8"));
}

const css = fs.readFileSync(path.join(source, stylesheet), "utf8");
fs.writeFileSync(
  output,
  [
    `// Generated by scripts/embed-interface-bundle.mjs from Atlas Interface Kit v${version}.`,
    `export const RAMONE_INTERFACE_VERSION = ${JSON.stringify(version)};`,
    `export const RAMONE_INTERFACE_SHA256 = ${JSON.stringify(manifest.files[stylesheet].sha256)};`,
    `export const RAMONE_INTERFACE_CSS = ${JSON.stringify(css)};`,
    "",
  ].join("\n"),
  "utf8",
);

console.log(
  `generated ${path.relative(root, output)} from Atlas Interface Kit v${version}`,
);
